+		return nil, fmt.Errorf("get comments for ephemeral issue %s: %w", issueID, err)
+	}
+	defer rows.Close()
+
+	var comments []*types.Comment
+	for rows.Next() {
+		var c types.Comment
+		var createdAt sql.NullString
+		if err := rows.Scan(&c.ID, &c.IssueID, &c.Author, &c.Text, &createdAt); err != nil {
